mapper.select:
select tc.id, tc.create_by, tc.update_by, tc.create_time, tc.update_time, tc.delete_flag, tc.customer_name, tc.phone, tc.wechat, tc.email, tc.channel, tc.capital, tc.mode, tc.data_source, tc.dev_status, tcs_progress.progress from t_customer tc left join ( -- 子表筛选未删除的数据，并获取每个客户最新沟通记录 select customer_id, progress, row_number() over (partition by customer_id order by communication_time desc) as rn from t_customer_sub tcs where tcs.delete_flag = 0 -- 子表只查未删除的记录 ) tcs_progress on tc.id = tcs_progress.customer_id and tcs_progress.rn = 1
tc.delete_flag = 0 and tc.customer_name like concat('%', #{customerName}, '%') and tc.create_by = #{createBy} and tc.phone like concat('%', #{phone}, '%') and tc.wechat like concat('%', #{wechat}, '%') and tc.email like concat('%', #{email}, '%') and tc.channel like concat('%', #{channel}, '%') and tc.capital like concat('%', #{capital}, '%') and tc.mode like concat('%', #{mode}, '%') and tc.data_source = #{dataSource} and tc.dev_status = #{devStatus} AND tc.create_time >= #{params.beginTime} AND tc.create_time <= #{params.endTime}
ORDER BY tc.create_time DESC

