mapper.select:
WITH idList AS ( SELECT id FROM t_customer
delete_flag = 0 and customer_name like concat('%', #{customerName}, '%') and phone like concat('%', #{phone}, '%') and wechat like concat('%', #{wechat}, '%') and email like concat('%', #{email}, '%') and channel like concat('%', #{channel}, '%') and capital like concat('%', #{capital}, '%') and mode like concat('%', #{mode}, '%') and data_source = #{dataSource} and dev_status = #{devStatus} AND create_time >= #{params.beginTime} AND create_time <= #{params.endTime}
), latest_customer_sub AS ( SELECT t1.customer_id,t1.progress FROM t_customer_sub t1 INNER JOIN ( SELECT customer_id, MAX(create_time) as last_create_time FROM t_customer_sub WHERE delete_flag = 0 GROUP BY customer_id ) t2 ON t1.customer_id = t2.customer_id AND t1.create_time= t2.last_create_time WHERE t1.delete_flag = 0 )
SELECT st.progress as progress,
FROM t_customer LEFT JOIN latest_customer_sub as st ON t_customer.id = st.customer_id WHERE t_customer.id in (select id from idList)
